<?php
declare(strict_types=1);
$root=require dirname(__DIR__).'/bootstrap/app.php';
use Vigilancia\Database\Connection;use Vigilancia\Repositories\PermissionRepository;use Vigilancia\Services\AuthService;use Vigilancia\Services\AuthorizationService;use Vigilancia\Services\ScopeService;use Vigilancia\Support\Config;use Vigilancia\Support\Session;
Session::start();$pdo=Connection::make(Config::database());$actor=(new AuthService($pdo))->current();(new AuthorizationService(new PermissionRepository($pdo)))->require($actor,'access_identifications.view');$type=($_GET['type']??'visit')==='provider'?'provider':'visit';$id=(int)($_GET['id']??0);$file=($_GET['file']??'identification')==='person'?'person':'identification';
if($type==='visit'){$column=$file==='person'?'va.visitor_photo_path':'va.identification_photo_path';$s=$pdo->prepare("SELECT $column asset_path,vp.location_id FROM visitor_accesses va JOIN visitor_passes vp ON vp.id=va.visitor_pass_id WHERE va.id=?");}
else{$column=$file==='person'?'pa.person_photo_path':'pa.identification_photo_path';$s=$pdo->prepare("SELECT $column asset_path,pa.location_id FROM provider_accesses pa WHERE pa.id=?");}$s->execute([$id]);$row=$s->fetch();if(!$row||!$row['asset_path']){http_response_code(404);exit('Evidencia no encontrada.');}if(!(new ScopeService($pdo))->location($actor,(int)$row['location_id'])){http_response_code(403);exit('Acceso denegado.');}$path=$root.'/'.$row['asset_path'];if(!is_file($path)){http_response_code(404);exit('Archivo no encontrado.');}header('Content-Type: '.((new finfo(FILEINFO_MIME_TYPE))->file($path)?:'application/octet-stream'));header('Content-Disposition: inline; filename="evidencia-'.$type.'-'.$id.'"');header('Cache-Control: private, no-store');readfile($path);
